    // Permission handling
    public boolean hasLocationPermission() {
        return ContextCompat.checkSelfPermission(this,
                Manifest.permission.ACCESS_FINE_LOCATION) == PackageManager.PERMISSION_GRANTED;
    }

    public boolean hasCameraPermission() {
        return ContextCompat.checkSelfPermission(this,
                Manifest.permission.CAMERA) == PackageManager.PERMISSION_GRANTED;
    }

    public void requestLocationPermission() {
        ActivityCompat.requestPermissions(this,
                new String[]{
                        Manifest.permission.ACCESS_FINE_LOCATION,
                        Manifest.permission.ACCESS_COARSE_LOCATION
                },
                PERMISSION_REQUEST_CODE);
    }

    public void requestCameraPermission() {
        ActivityCompat.requestPermissions(this,
                new String[]{Manifest.permission.CAMERA},
                PERMISSION_REQUEST_CODE + 1);
    }

    @Override
    public void onRequestPermissionsResult(int requestCode, @NonNull String[] permissions,
                                           @NonNull int[] grantResults) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults);
        if (grantResults.length > 0 && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
            Log.d(TAG, "Permission granted for request code: " + requestCode);
        } else {
            Toast.makeText(this, "Permission denied", Toast.LENGTH_SHORT).show();
        }
    }

    @SuppressLint("MissingPermission")
    public void fetchLocation(String callbackId) {
        if (!hasLocationPermission()) {
            requestLocationPermission();
            resolveCallback(callbackId, null, "Location permission not granted");
            return;
        }

        fusedLocationClient.getLastLocation()
                .addOnSuccessListener(this, location -> {
                    if (location != null) {
                        String json = String.format(Locale.US,
                                "{\"latitude\":%f,\"longitude\":%f,\"accuracy\":%f,\"altitude\":%f}",
                                location.getLatitude(), location.getLongitude(),
                                location.getAccuracy(), location.getAltitude());
                        resolveCallback(callbackId, json, null);
                    } else {
                        resolveCallback(callbackId, null, "Location not available");
                    }
                })
                .addOnFailureListener(this, e -> {
                    resolveCallback(callbackId, null, e.getMessage());
                });
    }

    public void launchCamera(String callbackId) {
        if (!hasCameraPermission()) {
            requestCameraPermission();
            resolveCallback(callbackId, null, "Camera permission not granted");
            return;
        }

        Intent takePictureIntent = new Intent(MediaStore.ACTION_IMAGE_CAPTURE);
        if (takePictureIntent.resolveActivity(getPackageManager()) != null) {
            File photoFile = null;
            try {
                photoFile = createImageFile();
            } catch (IOException ex) {
                resolveCallback(callbackId, null, "Failed to create image file");
                return;
            }

            if (photoFile != null) {
                Uri photoURI = FileProvider.getUriForFile(this,
                        getPackageName() + ".fileprovider",
                        photoFile);
                cameraPhotoPath = photoURI.toString();
                takePictureIntent.putExtra(MediaStore.EXTRA_OUTPUT, photoURI);
                cameraLauncher.launch(takePictureIntent);

                // Store callback for later resolution
                String json = String.format("{\"photoPath\":\"%s\"}", cameraPhotoPath);
                resolveCallback(callbackId, json, null);
            }
        }
    }

    private File createImageFile() throws IOException {
        String timeStamp = new SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(new Date());
        String imageFileName = "JPEG_" + timeStamp + "_";
        File storageDir = getExternalFilesDir(Environment.DIRECTORY_PICTURES);
        return File.createTempFile(imageFileName, ".jpg", storageDir);
    }

    public void handlePayment(String amount, String description, String merchantId, String callbackId) {
        runOnUiThread(() -> {
            new AlertDialog.Builder(this)
                    .setTitle("Confirm Payment")
                    .setMessage(String.format("Pay %s for %s?", amount, description))
                    .setPositiveButton("Pay", (dialog, which) -> {
                        // Initiate UPI payment
                        try {
                            Uri uri = Uri.parse("upi://pay")
                                    .buildUpon()
                                    .appendQueryParameter("pa", merchantId)
                                    .appendQueryParameter("pn", "Merchant")
                                    .appendQueryParameter("tn", description)
                                    .appendQueryParameter("am", amount)
                                    .appendQueryParameter("cu", "INR")
                                    .build();

                            Intent intent = new Intent(Intent.ACTION_VIEW, uri);
                            if (intent.resolveActivity(getPackageManager()) != null) {
                                startActivity(intent);
                                resolveCallback(callbackId,
                                        "{\"status\":\"initiated\",\"amount\":\"" + amount + "\"}",
                                        null);
                            } else {
                                // Fallback - simulate payment for MVP
                                resolveCallback(callbackId,
                                        "{\"status\":\"no_upi_app\",\"message\":\"No UPI app found\"}",
                                        null);
                            }
                        } catch (Exception e) {
                            resolveCallback(callbackId, null, e.getMessage());
                        }
                    })
                    .setNegativeButton("Cancel", (dialog, which) -> {
                        resolveCallback(callbackId, null, "Payment cancelled by user");
                    })
                    .show();
        });
    }

    public void resolveCallback(String callbackId, String data, String error) {
        runOnUiThread(() -> {
            if (error != null) {
                String script = String.format(
                        "window.HybridApp._rejectCallback('%s', '%s');",
                        callbackId, error.replace("'", "\\'"));
                webView.evaluateJavascript(script, null);
            } else {
                String script = String.format(
                        "window.HybridApp._resolveCallback('%s', '%s');",
                        callbackId, data.replace("'", "\\'"));
                webView.evaluateJavascript(script, null);
            }
        });
    }

    @Override
    public void onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack();
        } else {
            new AlertDialog.Builder(this)
                    .setTitle("Exit App")
                    .setMessage("Are you sure you want to exit?")
                    .setPositiveButton("Yes", (dialog, which) -> finish())
                    .setNegativeButton("No", null)
                    .show();
        }
    }

